/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel with:
 * - Phone number validation: checks that the recipient is a valid phone number
 * - Message formatting: converts NotificationPayload to a concise SMS message
 * - Configurable transport: accepts an SmsTransport for actual delivery
 *   (defaults to an in-memory transport for development/testing)
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) was designed
 * assuming email-only channels. It needs to be updated to support per-channel
 * preferences (e.g. SMS enabled/disabled, SMS subscribed categories). See the
 * warning posted to Twining for details on what needs to change.
 */

import type { NotificationAdapter, SendResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Record of an SMS that was sent (or attempted).
 */
export interface SentSms {
  to: string;
  message: string;
  sentAt: Date;
}

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  /** Sender ID or phone number shown as the sender. */
  fromNumber: string;
}

/**
 * Transport interface — abstracts how SMS messages are actually delivered.
 * Implement this for Twilio, AWS SNS, etc.
 */
export interface SmsTransport {
  sendSms(to: string, message: string): Promise<{ success: boolean; errorMessage?: string }>;
}

/**
 * Default in-memory transport: stores SMS messages in an array.
 * Suitable for development and testing.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: SentSms[] = [];

  async sendSms(to: string, message: string): Promise<{ success: boolean; errorMessage?: string }> {
    this.sent.push({ to, message, sentAt: new Date() });
    return { success: true };
  }

  getSentMessages(): SentSms[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

/**
 * E.164 phone number format: + followed by 1-15 digits.
 */
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

/**
 * Validates that a recipient string looks like a valid E.164 phone number.
 */
export function isValidPhoneNumber(phone: string): boolean {
  return PHONE_REGEX.test(phone);
}

/**
 * Formats a NotificationPayload into a concise SMS message.
 * SMS has a 160-character limit for a single segment, so we keep it short.
 */
export function formatSmsMessage(payload: NotificationPayload): string {
  const message = `${payload.subject}: ${payload.body}`;
  if (message.length > 160) {
    return message.substring(0, 157) + '...';
  }
  return message;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private transport: SmsTransport;
  private config: SmsAdapterConfig;

  constructor(
    config?: Partial<SmsAdapterConfig>,
    transport?: SmsTransport,
  ) {
    this.config = {
      fromNumber: config?.fromNumber ?? '+10000000000',
    };
    this.transport = transport ?? new InMemorySmsTransport();
  }

  /**
   * Send an SMS notification.
   *
   * 1. Validates the recipient phone number
   * 2. Formats the notification payload into a concise message
   * 3. Delegates to the configured transport
   *
   * Never throws — returns SendResult with success: false on failure.
   */
  async send(payload: NotificationPayload): Promise<SendResult> {
    try {
      if (!payload.recipient || !isValidPhoneNumber(payload.recipient)) {
        this.logger.warn(`Invalid phone number: ${payload.recipient}`);
        return { success: false, errorMessage: `Invalid phone number: ${payload.recipient}` };
      }

      const message = formatSmsMessage(payload);

      this.logger.info(`Sending SMS to ${payload.recipient}: ${payload.subject}`);

      const result = await this.transport.sendSms(payload.recipient, message);
      if (!result.success) {
        this.logger.error(`SMS delivery failed for ${payload.recipient}: ${result.errorMessage ?? 'unknown'}`);
        return { success: false, errorMessage: result.errorMessage };
      }

      return { success: true };
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Unexpected error sending SMS: ${message}`);
      return { success: false, errorMessage: message };
    }
  }

  /**
   * Get sent messages (only works with InMemorySmsTransport).
   */
  getSentMessages(): SentSms[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getSentMessages();
    }
    return [];
  }

  /**
   * Clear sent messages (only works with InMemorySmsTransport).
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }
}

