import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  isValidPhoneNumber,
  formatSmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { SmsTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Test Subject',
    body: 'Test body content.',
    channel: 'sms',
    priority: 'normal',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let transport: InMemorySmsTransport;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ fromNumber: '+15550000000' }, transport);
  });

  describe('send', () => {
    it('should send an SMS through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.message).toContain('Test Subject');
      expect(sent[0]?.message).toContain('Test body content.');
    });

    it('should reject invalid phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-phone' }));

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid phone number');
      expect(transport.getSentMessages()).toHaveLength(0);
    });

    it('should reject empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid phone number');
    });

    it('should handle transport failures gracefully', async () => {
      const failingTransport: SmsTransport = {
        async sendSms() {
          return { success: false, errorMessage: 'Service unavailable' };
        },
      };
      const failAdapter = new SmsAdapter({ fromNumber: '+15550000000' }, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('Service unavailable');
    });

    it('should catch transport exceptions and return SendResult', async () => {
      const throwingTransport: SmsTransport = {
        async sendSms() {
          throw new Error('Network timeout');
        },
      };
      const throwAdapter = new SmsAdapter({ fromNumber: '+15550000000' }, throwingTransport);

      const result = await throwAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('Network timeout');
    });

    it('should set the channel property to sms', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('getSentMessages / clearSentMessages', () => {
    it('should return sent messages from in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559876543' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();

      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return empty array for non-InMemorySmsTransport', () => {
      const customAdapter = new SmsAdapter(
        { fromNumber: '+15550000000' },
        { async sendSms() { return { success: true }; } },
      );
      expect(customAdapter.getSentMessages()).toEqual([]);
    });
  });
});

describe('isValidPhoneNumber', () => {
  it('should accept valid E.164 phone numbers', () => {
    expect(isValidPhoneNumber('+15551234567')).toBe(true);
    expect(isValidPhoneNumber('+442071234567')).toBe(true);
    expect(isValidPhoneNumber('+8613800138000')).toBe(true);
  });

  it('should reject invalid phone numbers', () => {
    expect(isValidPhoneNumber('')).toBe(false);
    expect(isValidPhoneNumber('5551234567')).toBe(false);
    expect(isValidPhoneNumber('+0123456789')).toBe(false);
    expect(isValidPhoneNumber('not-a-phone')).toBe(false);
    expect(isValidPhoneNumber('+1')).toBe(false);
  });
});

describe('formatSmsMessage', () => {
  it('should format payload into a concise message', () => {
    const payload = makePayload();
    const message = formatSmsMessage(payload);

    expect(message).toBe('Test Subject: Test body content.');
  });

  it('should truncate messages longer than 160 characters', () => {
    const longBody = 'A'.repeat(200);
    const payload = makePayload({ body: longBody });
    const message = formatSmsMessage(payload);

    expect(message.length).toBe(160);
    expect(message.endsWith('...')).toBe(true);
  });

  it('should not truncate messages at exactly 160 characters', () => {
    // "Test Subject: " is 14 chars, so body of 146 chars = exactly 160
    const exactBody = 'B'.repeat(146);
    const payload = makePayload({ body: exactBody });
    const message = formatSmsMessage(payload);

    expect(message.length).toBe(160);
    expect(message.endsWith('...')).toBe(false);
  });
});

